# Helper Functions
# ============================================================================

def encrypt_secret_value(secret_value: str | None = None, public_key: str | None = None) -> str | None:
    """Helper function for parameter transformation"""
    if secret_value is None or public_key is None:
        return None

    if nacl is None:
        raise ValueError("PyNaCl library is required for secret encryption. Install it with: pip install pynacl") from None

    try:
        public_key_bytes = base64.b64decode(public_key)
        public_key_obj = nacl.public.PublicKey(public_key_bytes)
        sealed_box = nacl.public.SealedBox(public_key_obj)
        encrypted = sealed_box.encrypt(secret_value.encode())
        encrypted_b64 = base64.b64encode(bytes(encrypted)).decode('utf-8')
        return encrypted_b64
    except (ValueError, TypeError) as e:
        raise ValueError(f"Failed to encrypt secret value: {e}") from e
    except Exception as e:
        raise ValueError(f"Encryption error: {e}") from e

def parse_author(value: str | None = None) -> dict | None:
    """Helper function for parameter transformation"""
    if value is None:
        return None
    value = value.strip()
    if '<' in value and '>' in value:
        name_part = value[:value.index('<')].strip()
        email_part = value[value.index('<')+1:value.index('>')].strip()
        if not email_part:
            raise ValueError('Email cannot be empty') from None
        return {'name': name_part if name_part else email_part.split('@')[0], 'email': email_part}
    else:
        if '@' not in value:
            raise ValueError('Invalid email format') from None
        return {'name': value.split('@')[0], 'email': value}

def build_review_comments(comment_path: str | None = None, comment_position: int | None = None, comment_line: int | None = None, comment_body: str | None = None) -> list[dict] | None:
    """Helper function for parameter transformation"""
    if all(v is None for v in [comment_path, comment_position, comment_line, comment_body]):
        return None

    if comment_path is None or comment_body is None:
        raise ValueError("comment_path and comment_body are required for review comments") from None

    if comment_position is None and comment_line is None:
        raise ValueError("Either comment_position or comment_line must be specified") from None

    comment_obj: dict[str, str | int] = {
        "path": comment_path,
        "body": comment_body
    }

    if comment_position is not None:
        comment_obj["position"] = comment_position

    if comment_line is not None:
        comment_obj["line"] = comment_line

    return [comment_obj]

def build_search_query(keywords: list[str] | None = None, state: str | None = None, labels: list[str] | None = None, language: str | None = None, is_qualifier: str | None = None, author: str | None = None, assignee: str | None = None, repo: str | None = None, created_after: str | None = None, created_before: str | None = None) -> str | None:
    """Helper function for parameter transformation"""
    if all(v is None for v in [keywords, state, labels, language, is_qualifier, author, assignee, repo, created_after, created_before]):
        return None

    try:
        query_parts = []
        
        if keywords:
            query_parts.extend(keywords)
        
        if state:
            query_parts.append(f'state:{state}')
        
        if labels:
            for label in labels:
                query_parts.append(f'label:{label}')
        
        if language:
            query_parts.append(f'language:{language}')
        
        if is_qualifier:
            query_parts.append(f'is:{is_qualifier}')
        
        if author:
            query_parts.append(f'author:{author}')
        
        if assignee:
            query_parts.append(f'assignee:{assignee}')
        
        if repo:
            query_parts.append(f'repo:{repo}')
        
        if created_after:
            query_parts.append(f'created:>={created_after}')
        
        if created_before:
            query_parts.append(f'created:<={created_before}')
        
        if not query_parts:
            return None
        
        q = '+'.join(query_parts)
        return q
    except Exception as e:
        raise ValueError(f'Failed to build search query: {e}') from e

@overload
def _parse_int(v: str | int) -> int: ...
@overload
def _parse_int(v: None) -> None: ...
def _parse_int(v: str | int | None) -> int | None:
    """Convert a string representation of an integer to a Python int.

    Formatted integer parameters (int32, int64, uint64, etc.) are exposed as str
    in the tool signature to prevent JS float64 precision loss for large IDs.
    This helper converts them back to int before Pydantic model construction.
    None passes through for optional parameters.
    Raises ValueError for non-integer strings or unexpected types (e.g. bool).
    """
    if v is None:
        return None
    if isinstance(v, bool):
        raise ValueError(f"Expected an integer value, got {v!r}")
    if isinstance(v, int):
        return v
    try:
        return int(v)
    except (ValueError, TypeError) as _e:
        raise ValueError(f"Expected an integer value, got {v!r}") from _e

def _check_unique_items(v: list) -> list:
    """Validate that array items are unique (OAS uniqueItems: true)."""
    seen = []
    for item in v:
        if item in seen:
            raise ValueError("array items must be unique")
        seen.append(item)
    return v

def _log_tool_invocation(tool_name: str, method: str, path: str, request_id: str, _redact: str = "") -> None:
    """Log tool invocation. If _redact is set, that value is partially masked in the logged path."""
    log_path = path
    if _redact:
        log_path = log_path.replace(_redact, _redact[:4] + "***" if len(_redact) > 4 else "***")

    logging.info(
        f"Tool invoked: {tool_name}",
        extra={
            "request_id": request_id,
            "tool": tool_name,
            "method": method,
            "path": log_path,
            "timeout": DEFAULT_TIMEOUT
        }
    )

def _build_path(
    template: str,
    path_params: dict[str, Any],
) -> str:
    """Build path from template and parameters.

    Args:
        template: Path template with {param} placeholders
        path_params: Dictionary of parameter names to values

    Returns:
        Path with all  placeholders replaced

    Example:
        _build_path("/files/{fileId}/copy", {"fileId": "abc123"})
        Returns: "/files/abc123/copy"
    """
    result = template
    for key, value in path_params.items():
        result = result.replace("{" + key + "}", str(value))
    # Normalize double slashes from path param substitution (e.g. "/{path}" + "/foo")
    # but preserve "://" in URL-valued params (e.g. siteUrl="https://example.com")
    while "//" in result:
        cleaned = result.replace("://", ":%SCHEME%")
        cleaned = cleaned.replace("//", "/")
        cleaned = cleaned.replace(":%SCHEME%", "://")
        if cleaned == result:
            break
        result = cleaned
    return result

async def _execute_tool_request(
    tool_name: str,
    method: str,
    path: str,
    request_id: str,
    params: dict[str, Any] | None = None,
    body: Any = None,
    body_content_type: str | None = None,
    multipart_file_fields: list[str] | None = None,
    headers: dict[str, str] | None = None,
    cookies: dict[str, str] | None = None,
    raw_querystring: str | None = None,
) -> tuple[dict[str, Any] | ToolResult, int]:
    """
    Execute tool request with timeout handling and metrics recording.

    Returns:
        Tuple of (normalized_response_data_or_tool_result, status_code).
        Successful responses are normalized to dict format for Pydantic validation.
        Status code: HTTP status code from the API response.
    """
    start_time = time.time()
    try:
        # Wrap API call with timeout to prevent hanging
        async with asyncio.timeout(DEFAULT_TIMEOUT):
            # Call unified _make_request() which handles all resilience + security features
            result, status_code = await _make_request(
                method=method,
                path=path,
                params=params,
                body=body,
                body_content_type=body_content_type,
                multipart_file_fields=multipart_file_fields,
                headers=headers,
                cookies=cookies,
                tool_name=tool_name,
                request_id=request_id,
                raw_querystring=raw_querystring,
            )

        latency_ms = (time.time() - start_time) * 1000.0

        logging.info(f"Tool completed: {tool_name}", extra={"request_id": request_id, "latency_ms": f"{latency_ms:.2f}"})

        # Normalize response to dict and return with status code
        # Use "value" key for consistency with generated response models
        if isinstance(result, dict):
            return result, status_code
        return {"value": result}, status_code

    except asyncio.TimeoutError as e:
        latency_ms = (time.time() - start_time) * 1000.0

        # Request timed out
        logging.error(
            f"Tool timeout: {tool_name}",
            extra={
                "request_id": request_id,
                "tool": tool_name,
                "method": method,
                "path": path,
                "timeout": DEFAULT_TIMEOUT,
                "latency_ms": f"{latency_ms:.2f}"
            }
        )

        # Raise exception with structured error message for consistency
        # FastMCP will catch this and set isError: true in MCP response
        timeout_message = (
            f"Tool: {tool_name}\n"
            f"Error: Request timed out after {DEFAULT_TIMEOUT} seconds\n"
            f"ID: {request_id}"
        )
        raise asyncio.TimeoutError(timeout_message) from e

    except UpstreamAPIError as e:
        latency_ms = (time.time() - start_time) * 1000.0
        return ToolResult(
            content=e.error_message,
            structured_content={
                "ok": False,
                "status": e.status_code,
                "request_id": e.request_id,
                "method": e.method,
                "path": e.path,
                "error": e.error_message,
                "details": e.error_data,
            },
        ), e.status_code

    except ValueError:
        latency_ms = (time.time() - start_time) * 1000.0
        raise

    except ConnectionError:
        latency_ms = (time.time() - start_time) * 1000.0
        raise

    except Exception:
        latency_ms = (time.time() - start_time) * 1000.0
        raise
# ============================================================================
# Authentication
# ============================================================================

# Authentication scheme priority (most secure first)
AUTH_SCHEME_PRIORITY = [
    'OAuth2',
    'PersonalAccessToken',
]

# Initialize authentication handlers at server startup
_auth_handlers: dict[str, Any] = {}
try:
    _auth_handlers["OAuth2"] = _auth.OAuth2Auth()
    logging.info("Authentication configured: OAuth2")
except ValueError as e:
    # Extract credential names from error message (first sentence before "Leave empty")
    error_msg = str(e).split("Leave empty")[0].strip()
    logging.warning(f"Credentials for OAuth2 not configured: {error_msg}")
    _auth_handlers["OAuth2"] = None
try:
    _auth_handlers["PersonalAccessToken"] = _auth.BearerTokenAuth(env_var="BEARER_TOKEN", token_format="Bearer")
    logging.info("Authentication configured: PersonalAccessToken")
except ValueError as e:
    # Extract credential names from error message (first sentence before "Leave empty")
    error_msg = str(e).split("Leave empty")[0].strip()
    logging.warning(f"Credentials for PersonalAccessToken not configured: {error_msg}")
    _auth_handlers["PersonalAccessToken"] = None

# Warn only if NO auth handlers were successfully configured
if all(handler is None for handler in _auth_handlers.values()):
    logging.warning("Server will attempt unauthenticated requests (may fail if API requires auth)")

def _on_auth_failure() -> None:
    """Clear tokens on all auth handlers that support it (called on 401 response)."""
    for scheme_name, handler in _auth_handlers.items():
        if handler is not None and hasattr(handler, 'clear_token'):
            handler.clear_token()
            logging.info(f"Cleared token for auth scheme '{scheme_name}' after 401")

async def _get_auth_for_operation(operation_id: str) -> dict[str, dict[str, str]]:
    """Get authentication for specific operation (handles multi-auth with OR/AND logic).

    Args:
        operation_id: The operation ID (tool name) to get auth for

    Returns:
        Dictionary with 'headers', 'params', 'cookies', 'path_params' keys containing auth data
    """
    result: dict[str, dict[str, str]] = {"headers": {}, "params": {}, "cookies": {}, "path_params": {}}

    # Get auth requirements for this operation from auth module
    # Map structure: operation_id -> [[scheme1], [scheme2, scheme3]] (OR of AND groups)
    required_schemes = _auth.OPERATION_AUTH_MAP.get(operation_id)

    if required_schemes is None:
        # CRITICAL: Operation missing from OPERATION_AUTH_MAP
        # This indicates a bug in auth config generation - operation should be in map
        # Do NOT fall back to global security - this masks bugs and creates security gaps
        logging.error(
            f"SECURITY ERROR: Operation '{operation_id}' not found in OPERATION_AUTH_MAP. "
            f"This indicates a bug in auth config generation. "
            f"All operations should be explicitly mapped. "
            f"Proceeding with no authentication - REQUEST WILL LIKELY FAIL."
        )
        # Return empty auth (will likely fail at API, but surfaces the bug)
        return result

    # Sort OR groups by security priority (most secure first)
    # Each OR group is sorted internally by scheme priority
    def get_scheme_priority(scheme_name: str) -> int:
        """Get priority index for scheme (lower = higher priority)."""
        try:
            return AUTH_SCHEME_PRIORITY.index(scheme_name)
        except ValueError:
            # Unknown scheme - put at end
            return len(AUTH_SCHEME_PRIORITY)

    # Sort each OR group by priority, then sort OR groups by their best (lowest) priority
    sorted_schemes = []
    for scheme_list in required_schemes:
        # Sort schemes within AND group by priority (most secure first)
        sorted_group = sorted(scheme_list, key=get_scheme_priority)
        sorted_schemes.append(sorted_group)

    # Sort OR groups by the priority of their first (most secure) scheme
    sorted_schemes.sort(key=lambda group: get_scheme_priority(group[0]) if group else float('inf'))

    # Try each OR group in priority order (most secure first)
    for scheme_list in sorted_schemes:
        headers = {}
        params = {}
        cookies = {}
        path_params = {}
        all_succeeded = True

        # Handle AND group (multiple schemes in same list - all must succeed)
        for scheme_name in scheme_list:
            handler = _auth_handlers.get(scheme_name)
            if not handler:
                # Handler not configured (env vars missing)
                all_succeeded = False
                logging.debug(f"Auth scheme '{scheme_name}' not configured for {operation_id}")
                break

            try:
                # Try all injection methods (headers, params, cookies, path_params)
                # OAuth2 methods are async (token refresh/authorize); others are sync.
                import inspect as _inspect
                if hasattr(handler, 'get_auth_headers'):
                    _h = handler.get_auth_headers()
                    headers.update(await _h if _inspect.isawaitable(_h) else _h)
                if hasattr(handler, 'get_auth_params'):
                    _p = handler.get_auth_params()
                    params.update(await _p if _inspect.isawaitable(_p) else _p)
                if hasattr(handler, 'get_auth_cookies'):
                    _c = handler.get_auth_cookies()
                    cookies.update(await _c if _inspect.isawaitable(_c) else _c)
                if hasattr(handler, 'get_auth_path_params'):
                    _pp = handler.get_auth_path_params()
                    path_params.update(await _pp if _inspect.isawaitable(_pp) else _pp)
            except Exception as e:
                logging.debug(f"Auth scheme '{scheme_name}' failed for {operation_id}: {e}")
                all_succeeded = False
                break

        # If all schemes in AND group succeeded, use this auth
        if all_succeeded and (headers or params or cookies or path_params):
            result["headers"] = headers
            result["params"] = params
            result["cookies"] = cookies
            result["path_params"] = path_params
            logging.debug(f"Using auth for {operation_id}: schemes={scheme_list}")
            return result

    # No auth configured or all OR groups failed
    if required_schemes and required_schemes != [[]]:
        logging.warning(f"No configured auth handler found for {operation_id} (requires: {required_schemes})")

    return result

# ============================================================================
# FastMCP Server Initialization
# ============================================================================

mcp = FastMCP("GitHub", middleware=[_JsonCoercionMiddleware()])

# Tags: security-advisories
@mcp.tool()
async def list_advisories(
    ghsa_id: str | None = Field(None, description="Filter results to a specific GitHub Security Advisory (GHSA) identifier."),
    type_: Literal["reviewed", "malware", "unreviewed"] | None = Field(None, alias="type", description="Filter results by advisory type. Reviewed advisories are returned by default; use 'malware' to include malware advisories or 'unreviewed' for community-contributed advisories."),
    cve_id: str | None = Field(None, description="Filter results to a specific Common Vulnerabilities and Exposures (CVE) identifier."),
    ecosystem: Literal["rubygems", "npm", "pip", "maven", "nuget", "composer", "go", "rust", "erlang", "actions", "pub", "other", "swift"] | None = Field(None, description="Filter results to advisories affecting specific package ecosystems."),
    cwes: str | list[str] | None = Field(None, description="Filter results to advisories with specific Common Weakness Enumeration (CWE) identifiers. Accepts comma-separated values or array format."),
    is_withdrawn: bool | None = Field(None, description="Filter results to only withdrawn advisories when set to true."),
    affects: str | list[str] | None = Field(None, description="Filter results to advisories affecting specific packages, optionally with version constraints. Accepts comma-separated values or array format. Maximum 1000 packages per request; use package name alone or package@version format."),
    modified: str | None = Field(None, description="Filter results to advisories updated or published within a specified date or date range using GitHub search syntax."),
    epss_percentage: str | None = Field(None, description="Filter results to advisories with an Exploit Prediction Scoring System (EPSS) percentage score matching the specified value, representing the likelihood of exploitation."),
    epss_percentile: str | None = Field(None, description="Filter results to advisories with an EPSS percentile score matching the specified value, representing the relative rank of exploitation likelihood compared to other CVEs."),
    direction: Literal["asc", "desc"] | None = Field(None, description="Sort results in ascending or descending order."),
) -> dict[str, Any] | ToolResult:
    """Retrieve global security advisories filtered by various criteria such as identifier, type, ecosystem, and vulnerability metrics. By default, returns only GitHub-reviewed advisories excluding malware."""

    # Construct request model with validation
    try:
        _request = _models.SecurityAdvisoriesListGlobalAdvisoriesRequest(
            query=_models.SecurityAdvisoriesListGlobalAdvisoriesRequestQuery(ghsa_id=ghsa_id, type_=type_, cve_id=cve_id, ecosystem=ecosystem, cwes=cwes, is_withdrawn=is_withdrawn, affects=affects, modified=modified, epss_percentage=epss_percentage, epss_percentile=epss_percentile, direction=direction)
        )
    except pydantic.ValidationError as _validation_err:
        logging.error(f"Parameter validation failed for list_advisories: {_validation_err}")
        raise ValueError(f"Invalid parameters: {_validation_err.errors()}") from _validation_err

    # Extract parameters for API call
    _http_path = "/advisories"
    _http_query = _request.query.model_dump(by_alias=True, exclude_none=True) if _request.query else {}
    _http_headers = {}

    # Inject per-operation authentication
    _auth = await _get_auth_for_operation("list_advisories")
    _http_headers.update(_auth.get("headers", {}))

    _request_id = str(uuid.uuid4())
    _log_tool_invocation("list_advisories", "GET", _http_path, _request_id)

    # Execute request (returns normalized dict and status code)
    _response_data, _ = await _execute_tool_request(
        tool_name="list_advisories",
        method="GET",
        path=_http_path,
        request_id=_request_id,
        params=_http_query,
        headers=_http_headers,
    )

    return _response_data

